failure.message:
AssertionError: Failed to create submission: {"detail":"A submission is already pending review for this milestone. Wait for review or withdraw the existing submission."}
assert 400 in [200, 201]
 +  where 400 = <Response [400]>.status_code

AssertionError: Failed to approve submission: {"detail":"Submission not found"}
assert 404 == 200
 +  where 404 = <Response [404]>.status_code

AssertionError: Failed to get submission: {"detail":"Submission not found"}
assert 404 == 200
 +  where 404 = <Response [404]>.status_code
